python3 -c "
cache = {1: 1}

def collatz_len(n):
    if n in cache:
        return cache[n]
    if n % 2 == 0:
        result = 1 + collatz_len(n // 2)
    else:
        result = 1 + collatz_len(3 * n + 1)
    cache[n] = result
    return result

import sys
sys.setrecursionlimit(10000)

best_n, best_len = 1, 1
for n in range(1, 1_000_000):
    length = collatz_len(n)
    if length > best_len:
        best_len = length
        best_n = n

print(f'Starting number: {best_n}')
print(f'Sequence length: {best_len}')
"
